    '@javascript:gs.dateGenerate(\'' + fechaNormalizada + '\',\'end\')'
  );
  gr.setLimit(1);
  gr.query();

if (gr.next()) {
    log('Período resuelto para ' + fechaNormalizada + ': ' + gr.getUniqueValue());
